description:
Extend the existing Registry in baml-bridge to also collect renderer specifications during type registration.

Location: crates/baml-bridge/src/registry.rs

```rust
use crate::prompt::renderer::{RendererSpec, RendererKey, RendererDbSeed};

#[derive(Debug, Default)]
pub struct Registry {
    // existing fields...
    enums: IndexMap<String, Enum>,
    classes: IndexMap<(String, StreamingMode), Class>,
    // ... etc

    // NEW: renderer collection
    renderers: RendererDbSeed,
}

impl Registry {
    // NEW: renderer registration method
    pub fn register_renderer(&mut self, key: RendererKey, spec: RendererSpec) {
        self.renderers.insert(key, spec);
    }

    // NEW: build with renderers (returns both OutputFormatContent and RendererDbSeed)
    pub fn build_with_renderers(self, target: TypeIR) -> (OutputFormatContent, RendererDbSeed) {
        let output_format = OutputFormatContent {
            enums: Arc::new(self.enums),
            classes: Arc::new(self.classes),
            recursive_classes: Arc::new(self.recursive_classes),
            structural_recursive_aliases: Arc::new(self.structural_recursive_aliases),
            target,
        };

        (output_format, self.renderers)
    }
}
```

Existing build() should remain unchanged for backward compatibility - implement it in terms of build_with_renderers().0
